const rememberMeCheckbox = document.getElementById('rememberMe');
const loginForm = document.getElementById('loginForm');

function setCookie(name, value, days) {
  let expires = "";
  if (days) {
    const date = new Date();
    date.setTime(date.getTime() + (days * 24 * 60 * 60 * 1000));
    expires = "; expires=" + date.toUTCString();
  }
  document.cookie = name + "=" + (value || "") + expires + "; path=/";
}

function getCookie(name) {
  const nameEQ = name + "=";
  const ca = document.cookie.split(';');
  for (let i = 0; i < ca.length; i++) {
    let c = ca[i];
    while (c.charAt(0) === ' ') c = c.substring(1, c.length);
    if (c.indexOf(nameEQ) === 0) return c.substring(nameEQ.length, c.length);
  }
  return null;
}

function eraseCookie(name) {
  document.cookie = name + '=; Max-Age=-99999999;';
}

function handleLogin(username, password) {
  // Assume username and password are valid
  if (rememberMeCheckbox.checked) {
    const passwordHash = btoa(password); // Simple base64 encoding for demonstration
    setCookie('rememberMe', JSON.stringify({ username, passwordHash }), 30);
  } else {
    eraseCookie('rememberMe');
  }
  // Perform actual login logic here
}

function autoLogin() {
  const rememberMeData = getCookie('rememberMe');
  if (rememberMeData) {
    const { username, passwordHash } = JSON.parse(rememberMeData);
    // Validate cookie data here
    document.getElementById('username').value = username;
    // Decoding the password just for demonstration
    const password = atob(passwordHash);
    document.getElementById('password').value = password;
    // Automate form submission or login process
  }
}

loginForm.addEventListener('submit', function (e) {
  e.preventDefault();
  const username = document.getElementById('username').value;
  const password = document.getElementById('password').value;
  handleLogin(username, password);
});

document.addEventListener('DOMContentLoaded', autoLogin);